import 'package:flutter/material.dart';\nimport '../services/staff_auth_service.dart';\nimport 'staff/staff_dashboard.dart';\n\nclass StaffLoginPage extends StatefulWidget {\n  const StaffLoginPage({super.key});\n\n  @override\n  State<StaffLoginPage> createState() => _StaffLoginPageState();\n}\n\nclass _StaffLoginPageState extends State<StaffLoginPage> {\n  final TextEditingController staffIdController = TextEditingController();\n  final TextEditingController pinController = TextEditingController();\n  final StaffAuthService authService = StaffAuthService();\n  bool _isLoading = false;\n  \n  final List<Map<String, String>> staffList = [\n    {'id': 'staff_001', 'name': 'Rajesh Kumar', 'role': 'Dyeing Specialist'},\n    {'id': 'staff_002', 'name': 'Priya Sharma', 'role': 'Master Cutter'},\n    {'id': 'staff_003', 'name': 'Amit Patel', 'role': 'Senior Tailor'},\n    {'id': 'staff_004', 'name': 'Sneha Desai', 'role': 'Khakha Expert'},\n    {'id': 'staff_005', 'name': 'Vikram Singh', 'role': 'Maggam Artist'},\n  ];\n\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      body: Container(\n        decoration: BoxDecoration(\n          gradient: LinearGradient(\n            begin: Alignment.topCenter,\n            end: Alignment.bottomCenter,\n            colors: [\n              Colors.deepPurple.shade400,\n              Colors.deepPurple.shade800,\n            ],\n          ),\n        ),\n        child: SafeArea(\n          child: Center(\n            child: SingleChildScrollView(\n              padding: const EdgeInsets.all(24),\n              child: Column(\n                mainAxisAlignment: MainAxisAlignment.center,\n                children: [\n                  // Logo and title\n                  Container(\n                    padding: const EdgeInsets.all(20),\n                    decoration: BoxDecoration(\n                      color: Colors.white,\n                      shape: BoxShape.circle,\n                      boxShadow: [\n                        BoxShadow(\n                          color: Colors.black.withOpacity(0.1),\n                          spreadRadius: 5,\n                          blurRadius: 15,\n                        ),\n                      ],\n                    ),\n                    child: const Icon(\n                      Icons.work,\n                      size: 60,\n                      color: Colors.deepPurple,\n                    ),\n                  ),\n                  const SizedBox(height: 32),\n                  const Text(\n                    'SAPTHALA',\n                    style: TextStyle(\n                      fontSize: 32,\n                      fontWeight: FontWeight.bold,\n                      color: Colors.white,\n                      letterSpacing: 2,\n                    ),\n                  ),\n                  const Text(\n                    'Staff Portal',\n                    style: TextStyle(\n                      fontSize: 18,\n                      color: Colors.white70,\n                      letterSpacing: 1,\n                    ),\n                  ),\n                  const SizedBox(height: 48),\n                  \n                  // Login form\n                  Container(\n                    padding: const EdgeInsets.all(24),\n                    decoration: BoxDecoration(\n                      color: Colors.white,\n                      borderRadius: BorderRadius.circular(16),\n                      boxShadow: [\n                        BoxShadow(\n                          color: Colors.black.withOpacity(0.1),\n                          spreadRadius: 5,\n                          blurRadius: 15,\n                        ),\n                      ],\n                    ),\n                    child: Column(\n                      crossAxisAlignment: CrossAxisAlignment.stretch,\n                      children: [\n                        const Text(\n                          'Staff Login',\n                          style: TextStyle(\n                            fontSize: 24,\n                            fontWeight: FontWeight.bold,\n                            color: Colors.deepPurple,\n                          ),\n                          textAlign: TextAlign.center,\n                        ),\n                        const SizedBox(height: 24),\n                        \n                        // Staff ID dropdown\n                        DropdownButtonFormField<String>(\n                          value: _staffIdController.text.isEmpty ? null : _staffIdController.text,\n                          decoration: const InputDecoration(\n                            labelText: 'Select Staff Member',\n                            prefixIcon: Icon(Icons.person),\n                            border: OutlineInputBorder(),\n                          ),\n                          items: _staffList.map((staff) {\n                            return DropdownMenuItem<String>(\n                              value: staff['id'],\n                              child: Column(\n                                crossAxisAlignment: CrossAxisAlignment.start,\n                                mainAxisSize: MainAxisSize.min,\n                                children: [\n                                  Text(\n                                    staff['name']!,\n                                    style: const TextStyle(fontWeight: FontWeight.bold),\n                                  ),\n                                  Text(\n                                    staff['role']!,\n                                    style: TextStyle(\n                                      fontSize: 12,\n                                      color: Colors.grey[600],\n                                    ),\n                                  ),\n                                ],\n                              ),\n                            );\n                          }).toList(),\n                          onChanged: (value) {\n                            setState(() {\n                              _staffIdController.text = value ?? '';\n                            });\n                          },\n                        ),\n                        const SizedBox(height: 16),\n                        \n                        // PIN field\n                        TextField(\n                          controller: _pinController,\n                          decoration: const InputDecoration(\n                            labelText: 'PIN',\n                            prefixIcon: Icon(Icons.lock),\n                            border: OutlineInputBorder(),\n                            hintText: 'Enter your 4-digit PIN',\n                          ),\n                          obscureText: true,\n                          keyboardType: TextInputType.number,\n                          maxLength: 4,\n                        ),\n                        const SizedBox(height: 24),\n                        \n                        // Login button\n                        ElevatedButton(\n                          onPressed: _isLoading ? null : _handleLogin,\n                          style: ElevatedButton.styleFrom(\n                            backgroundColor: Colors.deepPurple,\n                            foregroundColor: Colors.white,\n                            padding: const EdgeInsets.symmetric(vertical: 16),\n                            shape: RoundedRectangleBorder(\n                              borderRadius: BorderRadius.circular(8),\n                            ),\n                          ),\n                          child: _isLoading\n                              ? const SizedBox(\n                                  height: 20,\n                                  width: 20,\n                                  child: CircularProgressIndicator(\n                                    strokeWidth: 2,\n                                    valueColor: AlwaysStoppedAnimation<Color>(Colors.white),\n                                  ),\n                                )\n                              : const Text(\n                                  'Login',\n                                  style: TextStyle(\n                                    fontSize: 16,\n                                    fontWeight: FontWeight.bold,\n                                  ),\n                                ),\n                        ),\n                        \n                        const SizedBox(height: 16),\n                        \n                        // Demo info\n                        Container(\n                          padding: const EdgeInsets.all(12),\n                          decoration: BoxDecoration(\n                            color: Colors.blue.shade50,\n                            borderRadius: BorderRadius.circular(8),\n                            border: Border.all(color: Colors.blue.shade200),\n                          ),\n                          child: Column(\n                            children: [\n                              Row(\n                                children: [\n                                  Icon(Icons.info, color: Colors.blue.shade600, size: 16),\n                                  const SizedBox(width: 8),\n                                  Text(\n                                    'Demo Credentials',\n                                    style: TextStyle(\n                                      fontWeight: FontWeight.bold,\n                                      color: Colors.blue.shade800,\n                                    ),\n                                  ),\n                                ],\n                              ),\n                              const SizedBox(height: 8),\n                              Text(\n                                'Select any staff member and use PIN: 1234',\n                                style: TextStyle(\n                                  fontSize: 12,\n                                  color: Colors.blue.shade700,\n                                ),\n                                textAlign: TextAlign.center,\n                              ),\n                            ],\n                          ),\n                        ),\n                      ],\n                    ),\n                  ),\n                ],\n              ),\n            ),\n          ),\n        ),\n      ),\n    );\n  }\n\n  Future<void> _handleLogin() async {\n    if (_staffIdController.text.isEmpty || _pinController.text.isEmpty) {\n      ScaffoldMessenger.of(context).showSnackBar(\n        const SnackBar(content: Text('Please fill in all fields')),\n      );\n      return;\n    }\n\n    setState(() => _isLoading = true);\n\n    try {\n      final staff = await _authService.loginStaff(\n        _staffIdController.text,\n        _pinController.text,\n      );\n\n      if (staff != null) {\n        if (mounted) {\n          Navigator.pushReplacement(\n            context,\n            MaterialPageRoute(\n              builder: (context) => const StaffDashboard(),\n            ),\n          );\n        }\n      } else {\n        if (mounted) {\n          ScaffoldMessenger.of(context).showSnackBar(\n            const SnackBar(\n              content: Text('Invalid credentials. Please try again.'),\n              backgroundColor: Colors.red,\n            ),\n          );\n        }\n      }\n    } catch (e) {\n      if (mounted) {\n        ScaffoldMessenger.of(context).showSnackBar(\n          SnackBar(\n            content: Text('Login failed: $e'),\n            backgroundColor: Colors.red,\n          ),\n        );\n      }\n    } finally {\n      if (mounted) {\n        setState(() => _isLoading = false);\n      }\n    }\n  }\n\n  @override\n  void dispose() {\n    _staffIdController.dispose();\n    _pinController.dispose();\n    super.dispose();\n  }\n}\n